  var baseSetLang=window.CvPSetLang;
  window.CvPSetLang=function(lang){
    if(!dictionaries[lang])lang='en';
    baseSetLang(lang);
    window.CvPCurLang=lang;
    var current=document.getElementById('languageCurrent');
    if(current){current.textContent=names[lang];current.style.setProperty('--language-ink',inks[lang]);current.setAttribute('aria-expanded','false');}
    var menu=document.getElementById('languageMenu');if(menu)menu.hidden=true;
    document.querySelectorAll('.language-option').forEach(function(button){button.setAttribute('aria-selected',String(button.dataset.lang===lang));});
    window.CvPCapMap=caps[lang];
    window.CvPUpdateGut();
  };
  window.CvPToggleLanguageMenu=function(){var menu=document.getElementById('languageMenu'),button=document.getElementById('languageCurrent'),open=menu.hidden;menu.hidden=!open;button.setAttribute('aria-expanded',String(open));};
  window.CvPChooseLang=function(lang){window.CvPSetLang(lang);document.getElementById('languageCurrent').focus();};
  function fmt(value,vars){return value.replace(/\{(\w+)\}/g,function(_,key){return vars[key]===undefined?'':vars[key];});}
  window.CvPUpdateGut=function(){
    var hardHits=CvPHard.filter(function(q){return CvPAnswers[q]===true;});
    var softHits=CvPSoft.filter(function(q){return CvPAnswers[q]===true;});
    var allHits=hardHits.concat(softHits),lang=window.CvPCurLang||'en',dict=dictionaries[lang]||dictionaries.en,map=caps[lang]||caps.en;
    var badgeEl=document.getElementById('gutBadge'),verdictEl=document.getElementById('gutVerdict'),capsEl=document.getElementById('gutCaps'),resultEl=document.getElementById('gutResult');
    var isPlatform=hardHits.length>0||softHits.length>=CvPSoftThreshold;resultEl.classList.remove('core','platform');
    if(isPlatform){badgeEl.textContent='Platform';resultEl.classList.add('platform');if(hardHits.length){verdictEl.textContent=fmt(dict.gut_hard,{labels:hardHits.map(function(q){return map[q];}).join(', ')});}else{verdictEl.textContent=fmt(dict.gut_soft_many,{count:softHits.length});}}
    else{badgeEl.textContent='Core';resultEl.classList.add('core');verdictEl.textContent=softHits.length?fmt(dict.gut_soft_few,{count:softHits.length}):dict.gut_core_default;}
    if(allHits.length){capsEl.innerHTML='<div class="gut-caps-label">'+dict.gut_pulling+'</div>'+allHits.map(function(q){var hard=CvPHard.indexOf(q)!==-1;return '<span class="gcap'+(hard?' hard':'')+'">'+map[q]+(hard?' ('+dict.gut_hard_tag+')':'')+'</span>';}).join('');}else{capsEl.innerHTML='';}
  };
  document.addEventListener('click',function(event){var picker=event.target.closest('.language-picker');if(!picker){var menu=document.getElementById('languageMenu'),button=document.getElementById('languageCurrent');if(menu&&!menu.hidden){menu.hidden=true;button.setAttribute('aria-expanded','false');}}});
  document.addEventListener('keydown',function(event){if(event.key==='Escape'){var menu=document.getElementById('languageMenu'),button=document.getElementById('languageCurrent');if(menu&&!menu.hidden){menu.hidden=true;button.setAttribute('aria-expanded','false');button.focus();}}});
  var saved=null;try{saved=localStorage.getItem('lang');}catch(e){}
  var browser=(navigator.language||'en');var initial=saved&&dictionaries[saved]?saved:(browser.toLowerCase().indexOf('pt')===0?'pt-BR':browser.split('-')[0]);if(!dictionaries[initial])initial='en';window.CvPSetLang(initial);
